func (q *QueryStatement) SQL() string {
	return sqlOpt("", q.Hint, " ") + q.Query.SQL()
}

func (q *Query) SQL() string {
	return sqlOpt("", q.With, " ") +
		q.Query.SQL() +
		sqlOpt(" ", q.OrderBy, "") +
		sqlOpt(" ", q.Limit, "") +
		sqlOpt(" ", q.ForUpdate, "") +
		strOpt(len(q.PipeOperators) > 0, " ") +
