func generateFromDDL(t *testing.T, root, ddl string, opts Options) string {
	t.Helper()

	schemaPath := filepath.Join(root, "schema.sql")
	writeTextFile(t, schemaPath, ddl)

	schema, err := NewDDLFileSource(schemaPath).Load(t.Context())
	if err != nil {
		t.Fatalf("Load() error = %v", err)
